effect.shader:
void main() {
    highp mat3 rgb2hsv = mat3(
         0.299,     0.587,    0.114,
        -0.14713,  -0.28886,  0.436,
         0.615,    -0.51499, -0.10001
    );
    highp mat3 hsv2rgb = mat3(
        1.0,  0.0,      1.13983,
        1.0, -0.39465, -0.58060,
        1.0,  2.03211,  0.0
    );
    float rad = hue * 0.0174533;
    highp mat3 huemat = mat3(
        1.0,  0.0,       0.0,
        0.0,  cos(rad),  sin(rad),
        0.0,  -sin(rad), cos(rad)
    );
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    highp vec3 rgb = texColor.rgb;
    lowp float a = texColor.a;
    highp vec3 yuv = rgb * rgb2hsc;
    //yuv.yz = yuv.yz * (saturation+1.0);
    yuv = yuv * huemat;
    rgb = yuv * hsv2rgb;
    //rgb = (rgb - 0.5) * (contrast+1.0) + 0.5 + brightness;
    gl_FragColor = vec4(rgb,a);
}
